import React, { useState } from "react";
import "./ConsultancyPage.css";
import { useNavigate } from "react-router-dom";
import { ArrowLeft } from "lucide-react";

const doctorsData = {
  "General Physician": [
    {
      name: "Dr. Rachna Kucheria",
      image: "https://cdn.pixabay.com/photo/2016/11/29/03/53/woman-1867431_1280.jpg",
      qualification:
        "MD (Community Medicine) AIIMS New Delhi, MD (Family Medicine) USC California, Obesity Medicine Certification (ABOM)",
      experience: "30+ years",
      languages: "Hindi, English",
      fee: "₹1000",
    },
    {
      name: "Dr. Rashmi Gupta Bajpai",
      image: "https://cdn.pixabay.com/photo/2017/03/02/20/51/woman-2112292_1280.jpg",
      qualification:
        "MBBS Govt Medical College, Trivandrum, MD (Medicine) Baba Farid University of Health Sciences",
      experience: "24+ years",
      languages: "Hindi, English, Malayalam, Punjabi",
      fee: "₹700",
    },
  ],
  Pediatrics: [
    {
      name: "Dr. Aditi Sharma",
      image: "https://cdn.pixabay.com/photo/2017/01/31/20/30/woman-2027667_1280.jpg",
      qualification:
        "MD Pediatrics, AIIMS Delhi. Specializes in child health and neonatal care.",
      experience: "15+ years",
      languages: "English, Hindi",
      fee: "₹800",
    },
  ],
};

const ConsultancyPage = () => {
  const [openSpecialty, setOpenSpecialty] = useState(null);
  const navigate = useNavigate();

  const toggleSpecialty = (specialty) => {
    setOpenSpecialty(openSpecialty === specialty ? null : specialty);
  };

  return (
    <div className="consultancy-page">
      {/* Back Button */}
      <button className="back-button" onClick={() => navigate(-1)}>
        <ArrowLeft size={20} />
        <span>Back</span>
      </button>

      {/* Header */}
      <h1 className="consultancy-title">Our Doctors</h1>
      <p className="consultancy-subtitle">
        We have handpicked some of the best doctors in key specialties. Whether you are
        looking for the best online general physicians or pediatricians, we’ve got you covered.
      </p>

      {/* Search Bar */}
      <div className="consultancy-search-box">
        <p>Search for a doctor or speciality below:</p>
        <div className="search-bar">
          <input
            type="text"
            placeholder="Type symptoms / speciality and search for a great doctor"
          />
          <button>Search</button>
        </div>
      </div>

      {/* Accordion Section */}
      <div className="accordion-container">
        {Object.keys(doctorsData).map((specialty) => (
          <div key={specialty} className="accordion-item">
            <div
              className={`accordion-header ${
                openSpecialty === specialty ? "open" : ""
              }`}
              onClick={() => toggleSpecialty(specialty)}
            >
              <h2>{specialty}</h2>
              <span>{openSpecialty === specialty ? "−" : "+"}</span>
            </div>

            {openSpecialty === specialty && (
              <div className="accordion-content">
                {doctorsData[specialty].map((doc, index) => (
                  <div className="doctor-card" key={index}>
                    <img src={doc.image} alt={doc.name} className="doctor-image" />
                    <div className="doctor-details">
                      <h3>{doc.name}</h3>
                      <p className="qualification">{doc.qualification}</p>
                      <p>
                        <strong>{doc.experience} experience</strong> | Speaks {doc.languages}
                      </p>
                    </div>
                    <div className="doctor-actions">
                      <p className="fee">{doc.fee}</p>
                      <button className="view-btn">View Profile</button>
                      <button className="book-btn">Book Appointment</button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default ConsultancyPage;
